     1→import { useMemo } from "react";
     2→import { Tag, Intent, Icon } from "@blueprintjs/core";
     3→import type { SolverInput, SolverOutput, EventAssignment, SolverEvent } from "@uptime/types";
     4→
     5→// ============================================================================
     6→// 1. SCHEDULE GANTT - Timeline showing each train's maintenance events
     7→// ============================================================================
     8→
     9→interface ScheduleGanttProps {
    10→  input: SolverInput;
    11→  assignments: EventAssignment[];
    12→  horizonWeeks: number;
    13→  maxTrains?: number;
    14→}
    15→
    16→const MAINTENANCE_COLORS: Record<string, string> = {
    17→  "mt-a": "#2965CC", // Blue - A-Check
    18→  "mt-b": "#29A634", // Green - B-Check
    19→  "mt-c": "#D99E0B", // Yellow - C-Check
    20→  "mt-d": "#CD4246", // Red - D-Overhaul
    21→};
    22→
    23→const MAINTENANCE_LABELS: Record<string, string> = {
    24→  "mt-a": "A",
    25→  "mt-b": "B",
    26→  "mt-c": "C",
    27→  "mt-d": "D",
    28→};
    29→
    30→export function ScheduleGantt({ input, assignments, horizonWeeks, maxTrains = 30 }: ScheduleGanttProps) {
    31→  const ganttData = useMemo(() => {
    32→    const eventMap = new Map(input.events.map(e => [e.id, e]));
    33→    const assetEvents = new Map<string, Array<{ event: SolverEvent; assignment: EventAssignment }>>();
    34→
    35→    for (const assignment of assignments) {
    36→      const event = eventMap.get(assignment.eventId);
    37→      if (!event) continue;
    38→
    39→      if (!assetEvents.has(event.assetId)) {
    40→        assetEvents.set(event.assetId, []);
    41→      }
    42→      assetEvents.get(event.assetId)!.push({ event, assignment });
    43→    }
    44→
    45→    // Sort by asset ID and take first N
    46→    const sortedAssets = Array.from(assetEvents.entries())
    47→      .sort((a, b) => a[0].localeCompare(b[0]))
    48→      .slice(0, maxTrains);
    49→
    50→    return sortedAssets;
    51→  }, [input, assignments, maxTrains]);
    52→
    53→  const weekWidth = 100 / horizonWeeks;
    54→
    55→  return (
    56→    <div>
    57→      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
    58→        <h4 style={{ margin: 0 }}>Maintenance Timeline by Train</h4>
    59→        <div style={{ display: "flex", gap: "12px", fontSize: "11px" }}>
    60→          {Object.entries(MAINTENANCE_COLORS).map(([id, color]) => (
    61→            <div key={id} style={{ display: "flex", alignItems: "center", gap: "4px" }}>
    62→              <div style={{ width: "12px", height: "12px", backgroundColor: color, borderRadius: "2px" }} />
    63→              <span>{MAINTENANCE_LABELS[id]}-Check</span>
    64→            </div>
    65→          ))}
    66→        </div>
    67→      </div>
    68→
    69→      {/* Header - Week numbers */}
    70→      <div style={{ display: "flex", borderBottom: "1px solid #E1E8ED", paddingBottom: "4px", marginBottom: "4px" }}>
    71→        <div style={{ width: "80px", flexShrink: 0, fontSize: "10px", color: "#5F6B7C" }}>Train</div>
    72→        <div style={{ flex: 1, display: "flex", position: "relative" }}>
    73→          {Array.from({ length: horizonWeeks }, (_, i) => (
    74→            <div
    75→              key={i}
    76→              style={{
    77→                width: `${weekWidth}%`,
    78→                textAlign: "center",
    79→                fontSize: "9px",
    80→                color: "#8A9BA8",
    81→              }}
    82→            >
    83→              {(i + 1) % Math.ceil(horizonWeeks / 13) === 0 ? `W${i + 1}` : ""}
    84→            </div>
    85→          ))}
    86→        </div>
    87→      </div>
    88→
    89→      {/* Rows - Each train */}
    90→      <div style={{ maxHeight: "400px", overflowY: "auto" }}>
    91→        {ganttData.map(([assetId, events]) => (
    92→          <div
    93→            key={assetId}
    94→            style={{
    95→              display: "flex",
    96→              height: "24px",
    97→              alignItems: "center",
    98→              borderBottom: "1px solid #F5F8FA",
    99→            }}
   100→          >
   101→            <div style={{
   102→              width: "80px",
   103→              flexShrink: 0,
   104→              fontSize: "10px",
   105→              fontFamily: "monospace",
   106→              color: assetId.startsWith("ALT") ? "#2965CC" : "#29A634"
   107→            }}>
   108→              {assetId}
   109→            </div>
   110→            <div style={{ flex: 1, position: "relative", height: "100%" }}>
   111→              {/* Background grid */}
   112→              <div style={{
   113→                position: "absolute",
   114→                inset: 0,
   115→                display: "flex",
   116→              }}>
   117→                {Array.from({ length: horizonWeeks }, (_, i) => (
   118→                  <div
   119→                    key={i}
   120→                    style={{
   121→                      width: `${weekWidth}%`,
   122→                      borderRight: i % 4 === 3 ? "1px solid #E1E8ED" : "1px solid #F5F8FA",
   123→                      height: "100%",
   124→                    }}
   125→                  />
   126→                ))}
   127→              </div>
   128→
   129→              {/* Events */}
   130→              {events.map(({ event, assignment }) => {
   131→                const left = (assignment.assignedPeriod / horizonWeeks) * 100;
   132→                const color = MAINTENANCE_COLORS[event.maintenanceTypeId] || "#5F6B7C";
   133→
   134→                return (
   135→                  <div
   136→                    key={event.id}
   137→                    title={`${event.maintenanceTypeId.toUpperCase()}: Week ${assignment.assignedPeriod + 1} (target: ${event.targetPeriod + 1}, deviation: ${assignment.deviation >= 0 ? "+" : ""}${assignment.deviation})`}
   138→                    style={{
   139→                      position: "absolute",
   140→                      left: `${left}%`,
   141→                      top: "2px",
   142→                      width: `${Math.max(weekWidth * 0.8, 1)}%`,
   143→                      height: "20px",
   144→                      backgroundColor: color,
   145→                      borderRadius: "3px",
   146→                      display: "flex",
   147→                      alignItems: "center",
   148→                      justifyContent: "center",
   149→                      color: "white",
   150→                      fontSize: "9px",
   151→                      fontWeight: 600,
   152→                      cursor: "pointer",
   153→                      zIndex: 1,
   154→                    }}
   155→                  >
   156→                    {MAINTENANCE_LABELS[event.maintenanceTypeId]}
   157→                  </div>
   158→                );
   159→              })}
   160→            </div>
   161→          </div>
   162→        ))}
   163→      </div>
   164→
   165→      {ganttData.length >= maxTrains && (
   166→        <p style={{ textAlign: "center", color: "#8A9BA8", fontSize: "11px", marginTop: "8px" }}>
   167→          Showing first {maxTrains} of {input.assets.length} trains
   168→        </p>
   169→      )}
   170→    </div>
   171→  );
   172→}
   173→
   174→// ============================================================================
   175→// 2. CONSTRAINT SATISFACTION - Visual proof that all constraints are met
   176→// ============================================================================
   177→
   178→interface ConstraintSatisfactionProps {
   179→  input: SolverInput;
   180→  output: SolverOutput;
   181→}
   182→
   183→interface ConstraintCheck {
   184→  name: string;
   185→  description: string;
   186→  passed: boolean;
   187→  details: string;
   188→  severity: "critical" | "warning" | "info";
   189→}
   190→
   191→export function ConstraintSatisfaction({ input, output }: ConstraintSatisfactionProps) {
   192→  const constraints = useMemo((): ConstraintCheck[] => {
   193→    if (!output.solution) return [];
   194→
   195→    const { assignments, workloadProfile } = output.solution;
   196→    const eventMap = new Map(input.events.map(e => [e.id, e]));
   197→    const capacity = input.constraints.weeklyManHours;
   198→
   199→    const checks: ConstraintCheck[] = [];
   200→
   201→    // 1. Capacity constraint
   202→    const overCapacityWeeks = workloadProfile.filter(p => p.manHours > capacity);
   203→    checks.push({
   204→      name: "Weekly Capacity",
   205→      description: `Max ${capacity.toLocaleString()} man-hours per week`,
   206→      passed: overCapacityWeeks.length === 0,
   207→      details: overCapacityWeeks.length === 0
   208→        ? `All ${workloadProfile.length} weeks within capacity`
   209→        : `${overCapacityWeeks.length} weeks exceed capacity`,
   210→      severity: "critical",
   211→    });
   212→
   213→    // 2. Time window constraint
   214→    let windowViolations = 0;
   215→    let totalEvents = 0;
   216→    for (const assignment of assignments) {
   217→      const event = eventMap.get(assignment.eventId);
   218→      if (!event) continue;
   219→      totalEvents++;
   220→      if (assignment.assignedPeriod < event.earliestPeriod || assignment.assignedPeriod > event.latestPeriod) {
   221→        windowViolations++;
   222→      }
   223→    }
   224→    checks.push({
   225→      name: "Maintenance Windows",
   226→      description: "Events scheduled within allowed time windows",
   227→      passed: windowViolations === 0,
   228→      details: windowViolations === 0
   229→        ? `All ${totalEvents} events within their windows`
   230→        : `${windowViolations} events outside allowed windows`,
   231→      severity: "critical",
   232→    });
   233→
   234→    // 3. All events scheduled
   235→    const unscheduled = input.events.length - assignments.length;
   236→    checks.push({
   237→      name: "Complete Coverage",
   238→      description: "All required maintenance events scheduled",
   239→      passed: unscheduled === 0,
   240→      details: unscheduled === 0
   241→        ? `All ${input.events.length} events successfully scheduled`
   242→        : `${unscheduled} events could not be scheduled`,
   243→      severity: "critical",
   244→    });
   245→
   246→    // 4. Compliance (on-target scheduling)
   247→    const onTarget = assignments.filter(a => Math.abs(a.deviation) <= 2).length;
   248→    const complianceRate = assignments.length > 0 ? onTarget / assignments.length : 1;
   249→    checks.push({
   250→      name: "Schedule Compliance",
   251→      description: "Events scheduled within 2 weeks of target",
   252→      passed: complianceRate >= 0.9,
   253→      details: `${onTarget}/${assignments.length} events (${(complianceRate * 100).toFixed(0)}%) on target`,
   254→      severity: "warning",
   255→    });
   256→
   257→    // 5. Workload balance
   258→    if (output.metrics) {
   259→      const cv = output.metrics.workloadCv;
   260→      checks.push({
   261→        name: "Workload Balance",
   262→        description: "Even distribution of work across weeks",
   263→        passed: cv < 0.5,
   264→        details: `Coefficient of variation: ${(cv * 100).toFixed(1)}% (${cv < 0.3 ? "excellent" : cv < 0.5 ? "good" : "needs improvement"})`,
   265→        severity: "info",
   266→      });
   267→    }
   268→
   269→    // 6. Fleet distribution per week
   270→    const alstomByWeek = new Map<number, number>();
   271→    const kinkiByWeek = new Map<number, number>();
   272→    for (const assignment of assignments) {
   273→      const event = eventMap.get(assignment.eventId);
   274→      if (!event) continue;
   275→      const asset = input.assets.find(a => a.id === event.assetId);
   276→      if (!asset) continue;
   277→
   278→      const week = assignment.assignedPeriod;
   279→      if (asset.assetType === "ALSTOM") {
   280→        alstomByWeek.set(week, (alstomByWeek.get(week) || 0) + 1);
   281→      } else {
   282→        kinkiByWeek.set(week, (kinkiByWeek.get(week) || 0) + 1);
   283→      }
   284→    }
   285→
   286→    const maxAlstomPerWeek = Math.max(...alstomByWeek.values(), 0);
   287→    const maxKinkiPerWeek = Math.max(...kinkiByWeek.values(), 0);
   288→    checks.push({
   289→      name: "Fleet Distribution",
   290→      description: "Both fleets maintained throughout horizon",
   291→      passed: true,
   292→      details: `Max per week: ${maxAlstomPerWeek} Alstom, ${maxKinkiPerWeek} Kinki`,
   293→      severity: "info",
   294→    });
   295→
   296→    return checks;
   297→  }, [input, output]);
   298→
   299→  return (
   300→    <div>
   301→      <h4 style={{ margin: "0 0 16px 0" }}>Constraint Satisfaction Proof</h4>
   302→
   303→      <div style={{ display: "grid", gap: "8px" }}>
   304→        {constraints.map((check, idx) => (
   305→          <div
   306→            key={idx}
   307→            style={{
   308→              display: "flex",
   309→              alignItems: "center",
   310→              gap: "12px",
   311→              padding: "12px 16px",
   312→              backgroundColor: check.passed ? "#F0FFF4" : check.severity === "critical" ? "#FFF5F5" : "#FFF8E1",
   313→              borderRadius: "6px",
   314→              border: `1px solid ${check.passed ? "#B7EB8F" : check.severity === "critical" ? "#FFCCCB" : "#FFE082"}`,
   315→            }}
   316→          >
   317→            <Icon
   318→              icon={check.passed ? "tick-circle" : check.severity === "critical" ? "cross-circle" : "warning-sign"}
   319→              intent={check.passed ? Intent.SUCCESS : check.severity === "critical" ? Intent.DANGER : Intent.WARNING}
   320→              size={20}
   321→            />
   322→            <div style={{ flex: 1 }}>
   323→              <div style={{ fontWeight: 600, fontSize: "13px" }}>{check.name}</div>
   324→              <div style={{ fontSize: "11px", color: "#5F6B7C" }}>{check.description}</div>
   325→            </div>
   326→            <div style={{ textAlign: "right" }}>
   327→              <Tag
   328→                minimal
   329→                intent={check.passed ? Intent.SUCCESS : check.severity === "critical" ? Intent.DANGER : Intent.WARNING}
   330→              >
   331→                {check.passed ? "PASSED" : "FAILED"}
   332→              </Tag>
   333→              <div style={{ fontSize: "10px", color: "#8A9BA8", marginTop: "2px" }}>{check.details}</div>
   334→            </div>
   335→          </div>
   336→        ))}
   337→      </div>
   338→    </div>
   339→  );
   340→}
   341→
   342→// ============================================================================
   343→// 3. WORKLOAD BY TYPE - Stacked histogram showing breakdown by maintenance type
   344→// ============================================================================
   345→
   346→interface WorkloadByTypeProps {
   347→  input: SolverInput;
   348→  assignments: EventAssignment[];
   349→  horizonWeeks: number;
   350→  capacity: number;
   351→}
   352→
   353→export function WorkloadByType({ input, assignments, horizonWeeks, capacity }: WorkloadByTypeProps) {
   354→  const stackedData = useMemo(() => {
   355→    const eventMap = new Map(input.events.map(e => [e.id, e]));
   356→
   357→    // Initialize data structure
   358→    const byWeekAndType: Map<number, Map<string, number>> = new Map();
   359→    for (let w = 0; w < horizonWeeks; w++) {
   360→      byWeekAndType.set(w, new Map([["mt-a", 0], ["mt-b", 0], ["mt-c", 0], ["mt-d", 0]]));
   361→    }
   362→
   363→    // Accumulate man-hours
   364→    for (const assignment of assignments) {
   365→      const event = eventMap.get(assignment.eventId);
   366→      if (!event) continue;
   367→
   368→      const weekData = byWeekAndType.get(assignment.assignedPeriod);
   369→      if (weekData) {
   370→        const current = weekData.get(event.maintenanceTypeId) || 0;
   371→        weekData.set(event.maintenanceTypeId, current + event.manHours);
   372→      }
   373→    }
   374→
   375→    return Array.from(byWeekAndType.entries()).map(([week, typeData]) => ({
   376→      week,
   377→      "A-Check": typeData.get("mt-a") || 0,
   378→      "B-Check": typeData.get("mt-b") || 0,
   379→      "C-Check": typeData.get("mt-c") || 0,
   380→      "D-Overhaul": typeData.get("mt-d") || 0,
   381→      total: (typeData.get("mt-a") || 0) + (typeData.get("mt-b") || 0) + (typeData.get("mt-c") || 0) + (typeData.get("mt-d") || 0),
   382→    }));
   383→  }, [input, assignments, horizonWeeks]);
   384→
   385→  const maxWorkload = Math.max(...stackedData.map(d => d.total), capacity) * 1.1;
   386→
   387→  return (
   388→    <div>
   389→      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
   390→        <h4 style={{ margin: 0 }}>Workload by Maintenance Type</h4>
   391→        <div style={{ display: "flex", gap: "12px", fontSize: "11px" }}>
   392→          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
   393→            <div style={{ width: "12px", height: "12px", backgroundColor: "#2965CC", borderRadius: "2px" }} />
   394→            <span>A-Check (8h)</span>
   395→          </div>
   396→          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
   397→            <div style={{ width: "12px", height: "12px", backgroundColor: "#29A634", borderRadius: "2px" }} />
   398→            <span>B-Check (32h)</span>
   399→          </div>
   400→          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
   401→            <div style={{ width: "12px", height: "12px", backgroundColor: "#D99E0B", borderRadius: "2px" }} />
   402→            <span>C-Check (160h)</span>
   403→          </div>
   404→          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
   405→            <div style={{ width: "12px", height: "12px", backgroundColor: "#CD4246", borderRadius: "2px" }} />
   406→            <span>D-Overhaul (1200h)</span>
   407→          </div>
   408→        </div>
   409→      </div>
   410→
   411→      <div style={{
   412→        position: "relative",
   413→        height: "200px",
   414→        display: "flex",
   415→        alignItems: "flex-end",
   416→        gap: "2px",
   417→        padding: "0 4px",
   418→        backgroundColor: "white",
   419→        borderRadius: "4px",
   420→        border: "1px solid #E1E8ED"
   421→      }}>
   422→        {/* Capacity line */}
   423→        <div
   424→          style={{
   425→            position: "absolute",
   426→            left: 0,
   427→            right: 0,
   428→            bottom: `${(capacity / maxWorkload) * 100}%`,
   429→            borderTop: "2px dashed #394B59",
   430→            zIndex: 10,
   431→          }}
   432→        >
   433→          <span style={{
   434→            position: "absolute",
   435→            right: "4px",
   436→            top: "-16px",
   437→            fontSize: "10px",
   438→            color: "#394B59",
   439→            fontWeight: 500,
   440→          }}>
   441→            Capacity: {capacity.toLocaleString()}
   442→          </span>
   443→        </div>
   444→
   445→        {/* Stacked bars */}
   446→        {stackedData.map((data, idx) => {
   447→          const aHeight = (data["A-Check"] / maxWorkload) * 100;
   448→          const bHeight = (data["B-Check"] / maxWorkload) * 100;
   449→          const cHeight = (data["C-Check"] / maxWorkload) * 100;
   450→          const dHeight = (data["D-Overhaul"] / maxWorkload) * 100;
   451→
   452→          return (
   453→            <div
   454→              key={data.week}
   455→              style={{
   456→                flex: 1,
   457→                display: "flex",
   458→                flexDirection: "column-reverse",
   459→                alignItems: "stretch",
   460→                height: "100%",
   461→              }}
   462→              title={`Week ${data.week + 1}: A=${data["A-Check"]}h, B=${data["B-Check"]}h, C=${data["C-Check"]}h, D=${data["D-Overhaul"]}h, Total=${data.total}h`}
   463→            >
   464→              {data["A-Check"] > 0 && (
   465→                <div style={{ height: `${aHeight}%`, backgroundColor: "#2965CC", minHeight: "2px" }} />
   466→              )}
   467→              {data["B-Check"] > 0 && (
   468→                <div style={{ height: `${bHeight}%`, backgroundColor: "#29A634", minHeight: "2px" }} />
   469→              )}
   470→              {data["C-Check"] > 0 && (
   471→                <div style={{ height: `${cHeight}%`, backgroundColor: "#D99E0B", minHeight: "2px" }} />
   472→              )}
   473→              {data["D-Overhaul"] > 0 && (
   474→                <div style={{ height: `${dHeight}%`, backgroundColor: "#CD4246", minHeight: "2px" }} />
   475→              )}
   476→            </div>
   477→          );
   478→        })}
   479→      </div>
   480→
   481→      {/* X-axis labels */}
   482→      <div style={{
   483→        display: "flex",
   484→        gap: "2px",
   485→        padding: "4px 4px 0",
   486→        fontSize: "9px",
   487→        color: "#5F6B7C"
   488→      }}>
   489→        {stackedData.map((data, idx) => (
   490→          <div key={data.week} style={{ flex: 1, textAlign: "center" }}>
   491→            {(idx % Math.ceil(horizonWeeks / 13) === 0) ? `W${data.week + 1}` : ""}
   492→          </div>
   493→        ))}
   494→      </div>
   495→    </div>
   496→  );
   497→}
   498→
   499→// ============================================================================
   500→// 4. EVENT WINDOW VISUALIZATION - Shows target vs actual with tolerance bands
   501→// ============================================================================
   502→
   503→interface EventWindowProps {
   504→  input: SolverInput;
   505→  assignments: EventAssignment[];
   506→  maxEvents?: number;
   507→}
   508→
   509→export function EventWindowVisualization({ input, assignments, maxEvents = 20 }: EventWindowProps) {
   510→  const eventData = useMemo(() => {
   511→    const eventMap = new Map(input.events.map(e => [e.id, e]));
   512→    const assetMap = new Map(input.assets.map(a => [a.id, a]));
   513→
   514→    return assignments
   515→      .map(assignment => {
   516→        const event = eventMap.get(assignment.eventId);
   517→        if (!event) return null;
   518→
   519→        const asset = assetMap.get(event.assetId);
   520→
   521→        return {
   522→          eventId: assignment.eventId,
   523→          assetId: event.assetId,
   524→          assetType: asset?.assetType || "Unknown",
   525→          maintenanceType: event.maintenanceTypeId,
   526→          earliest: event.earliestPeriod,
   527→          target: event.targetPeriod,
   528→          latest: event.latestPeriod,
   529→          assigned: assignment.assignedPeriod,
   530→          deviation: assignment.deviation,
   531→          isOnTarget: Math.abs(assignment.deviation) <= 2,
   532→        };
   533→      })
   534→      .filter(Boolean)
   535→      .slice(0, maxEvents);
   536→  }, [input, assignments, maxEvents]);
   537→
   538→  const horizonWeeks = input.planningHorizonWeeks;
   539→
   540→  return (
   541→    <div>
   542→      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
   543→        <h4 style={{ margin: 0 }}>Scheduling Windows & Assignments</h4>
   544→        <div style={{ display: "flex", gap: "16px", fontSize: "11px" }}>
   545→          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
