import { useMemo } from "react";
import { Tag, Intent, Icon } from "@blueprintjs/core";
import type { SolverInput, SolverOutput, EventAssignment, SolverEvent } from "@uptime/types";

// ============================================================================
// 1. SCHEDULE GANTT - Timeline showing each train's maintenance events
// ============================================================================

interface ScheduleGanttProps {
  input: SolverInput;
  assignments: EventAssignment[];
  horizonWeeks: number;
  maxTrains?: number;
}

const MAINTENANCE_COLORS: Record<string, string> = {
  "mt-a": "#2965CC", // Blue - A-Check
  "mt-b": "#29A634", // Green - B-Check
  "mt-c": "#D99E0B", // Yellow - C-Check
  "mt-d": "#CD4246", // Red - D-Overhaul
};

const MAINTENANCE_LABELS: Record<string, string> = {
  "mt-a": "A",
  "mt-b": "B",
  "mt-c": "C",
  "mt-d": "D",
};

export function ScheduleGantt({ input, assignments, horizonWeeks, maxTrains = 30 }: ScheduleGanttProps) {
  const ganttData = useMemo(() => {
    const eventMap = new Map(input.events.map(e => [e.id, e]));
    const assetEvents = new Map<string, Array<{ event: SolverEvent; assignment: EventAssignment }>>();

    for (const assignment of assignments) {
      const event = eventMap.get(assignment.eventId);
      if (!event) continue;

      if (!assetEvents.has(event.assetId)) {
        assetEvents.set(event.assetId, []);
      }
      assetEvents.get(event.assetId)!.push({ event, assignment });
    }

    // Sort by asset ID and take first N
    const sortedAssets = Array.from(assetEvents.entries())
      .sort((a, b) => a[0].localeCompare(b[0]))
      .slice(0, maxTrains);

    return sortedAssets;
  }, [input, assignments, maxTrains]);

  const weekWidth = 100 / horizonWeeks;

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
        <h4 style={{ margin: 0 }}>Maintenance Timeline by Train</h4>
        <div style={{ display: "flex", gap: "12px", fontSize: "11px" }}>
          {Object.entries(MAINTENANCE_COLORS).map(([id, color]) => (
            <div key={id} style={{ display: "flex", alignItems: "center", gap: "4px" }}>
              <div style={{ width: "12px", height: "12px", backgroundColor: color, borderRadius: "2px" }} />
              <span>{MAINTENANCE_LABELS[id]}-Check</span>
            </div>
          ))}
        </div>
      </div>

      {/* Header - Week numbers */}
      <div style={{ display: "flex", borderBottom: "1px solid #E1E8ED", paddingBottom: "4px", marginBottom: "4px" }}>
        <div style={{ width: "80px", flexShrink: 0, fontSize: "10px", color: "#5F6B7C" }}>Train</div>
        <div style={{ flex: 1, display: "flex", position: "relative" }}>
          {Array.from({ length: horizonWeeks }, (_, i) => (
            <div
              key={i}
              style={{
                width: `${weekWidth}%`,
                textAlign: "center",
                fontSize: "9px",
                color: "#8A9BA8",
              }}
            >
              {(i + 1) % Math.ceil(horizonWeeks / 13) === 0 ? `W${i + 1}` : ""}
            </div>
          ))}
        </div>
      </div>

      {/* Rows - Each train */}
      <div style={{ maxHeight: "400px", overflowY: "auto" }}>
        {ganttData.map(([assetId, events]) => (
          <div
            key={assetId}
            style={{
              display: "flex",
              height: "24px",
              alignItems: "center",
              borderBottom: "1px solid #F5F8FA",
            }}
          >
            <div style={{
              width: "80px",
              flexShrink: 0,
              fontSize: "10px",
              fontFamily: "monospace",
              color: assetId.startsWith("ALT") ? "#2965CC" : "#29A634"
            }}>
              {assetId}
            </div>
            <div style={{ flex: 1, position: "relative", height: "100%" }}>
              {/* Background grid */}
              <div style={{
                position: "absolute",
                inset: 0,
                display: "flex",
              }}>
                {Array.from({ length: horizonWeeks }, (_, i) => (
                  <div
                    key={i}
                    style={{
                      width: `${weekWidth}%`,
                      borderRight: i % 4 === 3 ? "1px solid #E1E8ED" : "1px solid #F5F8FA",
                      height: "100%",
                    }}
                  />
                ))}
              </div>

              {/* Events */}
              {events.map(({ event, assignment }) => {
                const left = (assignment.assignedPeriod / horizonWeeks) * 100;
                const color = MAINTENANCE_COLORS[event.maintenanceTypeId] || "#5F6B7C";

                return (
                  <div
                    key={event.id}
                    title={`${event.maintenanceTypeId.toUpperCase()}: Week ${assignment.assignedPeriod + 1} (target: ${event.targetPeriod + 1}, deviation: ${assignment.deviation >= 0 ? "+" : ""}${assignment.deviation})`}
                    style={{
                      position: "absolute",
                      left: `${left}%`,
                      top: "2px",
                      width: `${Math.max(weekWidth * 0.8, 1)}%`,
                      height: "20px",
                      backgroundColor: color,
                      borderRadius: "3px",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      color: "white",
                      fontSize: "9px",
                      fontWeight: 600,
                      cursor: "pointer",
                      zIndex: 1,
                    }}
                  >
                    {MAINTENANCE_LABELS[event.maintenanceTypeId]}
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>

      {ganttData.length >= maxTrains && (
        <p style={{ textAlign: "center", color: "#8A9BA8", fontSize: "11px", marginTop: "8px" }}>
          Showing first {maxTrains} of {input.assets.length} trains
        </p>
      )}
    </div>
  );
}

// ============================================================================
// 2. CONSTRAINT SATISFACTION - Visual proof that all constraints are met
// ============================================================================

interface ConstraintSatisfactionProps {
  input: SolverInput;
  output: SolverOutput;
}

interface ConstraintCheck {
  name: string;
  description: string;
  passed: boolean;
  details: string;
  severity: "critical" | "warning" | "info";
}

export function ConstraintSatisfaction({ input, output }: ConstraintSatisfactionProps) {
  const constraints = useMemo((): ConstraintCheck[] => {
    if (!output.solution) return [];

    const { assignments, workloadProfile } = output.solution;
    const eventMap = new Map(input.events.map(e => [e.id, e]));
    const capacity = input.constraints.weeklyManHours;

    const checks: ConstraintCheck[] = [];

    // 1. Capacity constraint
    const overCapacityWeeks = workloadProfile.filter(p => p.manHours > capacity);
    checks.push({
      name: "Weekly Capacity",
      description: `Max ${capacity.toLocaleString()} man-hours per week`,
      passed: overCapacityWeeks.length === 0,
      details: overCapacityWeeks.length === 0
        ? `All ${workloadProfile.length} weeks within capacity`
        : `${overCapacityWeeks.length} weeks exceed capacity`,
      severity: "critical",
    });

    // 2. Time window constraint
    let windowViolations = 0;
    let totalEvents = 0;
    for (const assignment of assignments) {
      const event = eventMap.get(assignment.eventId);
      if (!event) continue;
      totalEvents++;
      if (assignment.assignedPeriod < event.earliestPeriod || assignment.assignedPeriod > event.latestPeriod) {
        windowViolations++;
      }
    }
    checks.push({
      name: "Maintenance Windows",
      description: "Events scheduled within allowed time windows",
      passed: windowViolations === 0,
      details: windowViolations === 0
        ? `All ${totalEvents} events within their windows`
        : `${windowViolations} events outside allowed windows`,
      severity: "critical",
    });

    // 3. All events scheduled
    const unscheduled = input.events.length - assignments.length;
    checks.push({
      name: "Complete Coverage",
      description: "All required maintenance events scheduled",
      passed: unscheduled === 0,
      details: unscheduled === 0
        ? `All ${input.events.length} events successfully scheduled`
        : `${unscheduled} events could not be scheduled`,
      severity: "critical",
    });

    // 4. Compliance (on-target scheduling)
    const onTarget = assignments.filter(a => Math.abs(a.deviation) <= 2).length;
    const complianceRate = assignments.length > 0 ? onTarget / assignments.length : 1;
    checks.push({
      name: "Schedule Compliance",
      description: "Events scheduled within 2 weeks of target",
      passed: complianceRate >= 0.9,
      details: `${onTarget}/${assignments.length} events (${(complianceRate * 100).toFixed(0)}%) on target`,
      severity: "warning",
    });

    // 5. Workload balance
    if (output.metrics) {
      const cv = output.metrics.workloadCv;
      checks.push({
        name: "Workload Balance",
        description: "Even distribution of work across weeks",
        passed: cv < 0.5,
        details: `Coefficient of variation: ${(cv * 100).toFixed(1)}% (${cv < 0.3 ? "excellent" : cv < 0.5 ? "good" : "needs improvement"})`,
        severity: "info",
      });
    }

    // 6. Fleet distribution per week
    const alstomByWeek = new Map<number, number>();
    const kinkiByWeek = new Map<number, number>();
    for (const assignment of assignments) {
      const event = eventMap.get(assignment.eventId);
      if (!event) continue;
      const asset = input.assets.find(a => a.id === event.assetId);
      if (!asset) continue;

      const week = assignment.assignedPeriod;
      if (asset.assetType === "ALSTOM") {
        alstomByWeek.set(week, (alstomByWeek.get(week) || 0) + 1);
      } else {
        kinkiByWeek.set(week, (kinkiByWeek.get(week) || 0) + 1);
      }
    }

    const maxAlstomPerWeek = Math.max(...alstomByWeek.values(), 0);
    const maxKinkiPerWeek = Math.max(...kinkiByWeek.values(), 0);
    checks.push({
      name: "Fleet Distribution",
      description: "Both fleets maintained throughout horizon",
      passed: true,
      details: `Max per week: ${maxAlstomPerWeek} Alstom, ${maxKinkiPerWeek} Kinki`,
      severity: "info",
    });

    return checks;
  }, [input, output]);

  return (
    <div>
      <h4 style={{ margin: "0 0 16px 0" }}>Constraint Satisfaction Proof</h4>

      <div style={{ display: "grid", gap: "8px" }}>
        {constraints.map((check, idx) => (
          <div
            key={idx}
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              padding: "12px 16px",
              backgroundColor: check.passed ? "#F0FFF4" : check.severity === "critical" ? "#FFF5F5" : "#FFF8E1",
              borderRadius: "6px",
              border: `1px solid ${check.passed ? "#B7EB8F" : check.severity === "critical" ? "#FFCCCB" : "#FFE082"}`,
            }}
          >
            <Icon
              icon={check.passed ? "tick-circle" : check.severity === "critical" ? "cross-circle" : "warning-sign"}
              intent={check.passed ? Intent.SUCCESS : check.severity === "critical" ? Intent.DANGER : Intent.WARNING}
              size={20}
            />
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 600, fontSize: "13px" }}>{check.name}</div>
              <div style={{ fontSize: "11px", color: "#5F6B7C" }}>{check.description}</div>
            </div>
            <div style={{ textAlign: "right" }}>
              <Tag
                minimal
                intent={check.passed ? Intent.SUCCESS : check.severity === "critical" ? Intent.DANGER : Intent.WARNING}
              >
                {check.passed ? "PASSED" : "FAILED"}
              </Tag>
              <div style={{ fontSize: "10px", color: "#8A9BA8", marginTop: "2px" }}>{check.details}</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ============================================================================
// 3. WORKLOAD BY TYPE - Stacked histogram showing breakdown by maintenance type
// ============================================================================

interface WorkloadByTypeProps {
  input: SolverInput;
  assignments: EventAssignment[];
  horizonWeeks: number;
  capacity: number;
}

export function WorkloadByType({ input, assignments, horizonWeeks, capacity }: WorkloadByTypeProps) {
  const stackedData = useMemo(() => {
    const eventMap = new Map(input.events.map(e => [e.id, e]));

    // Initialize data structure
    const byWeekAndType: Map<number, Map<string, number>> = new Map();
    for (let w = 0; w < horizonWeeks; w++) {
      byWeekAndType.set(w, new Map([["mt-a", 0], ["mt-b", 0], ["mt-c", 0], ["mt-d", 0]]));
    }

    // Accumulate man-hours
    for (const assignment of assignments) {
      const event = eventMap.get(assignment.eventId);
      if (!event) continue;

      const weekData = byWeekAndType.get(assignment.assignedPeriod);
      if (weekData) {
        const current = weekData.get(event.maintenanceTypeId) || 0;
        weekData.set(event.maintenanceTypeId, current + event.manHours);
      }
    }

    return Array.from(byWeekAndType.entries()).map(([week, typeData]) => ({
      week,
      "A-Check": typeData.get("mt-a") || 0,
      "B-Check": typeData.get("mt-b") || 0,
      "C-Check": typeData.get("mt-c") || 0,
      "D-Overhaul": typeData.get("mt-d") || 0,
      total: (typeData.get("mt-a") || 0) + (typeData.get("mt-b") || 0) + (typeData.get("mt-c") || 0) + (typeData.get("mt-d") || 0),
    }));
  }, [input, assignments, horizonWeeks]);

  const maxWorkload = Math.max(...stackedData.map(d => d.total), capacity) * 1.1;

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
        <h4 style={{ margin: 0 }}>Workload by Maintenance Type</h4>
        <div style={{ display: "flex", gap: "12px", fontSize: "11px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div style={{ width: "12px", height: "12px", backgroundColor: "#2965CC", borderRadius: "2px" }} />
            <span>A-Check (8h)</span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div style={{ width: "12px", height: "12px", backgroundColor: "#29A634", borderRadius: "2px" }} />
            <span>B-Check (32h)</span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div style={{ width: "12px", height: "12px", backgroundColor: "#D99E0B", borderRadius: "2px" }} />
            <span>C-Check (160h)</span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div style={{ width: "12px", height: "12px", backgroundColor: "#CD4246", borderRadius: "2px" }} />
            <span>D-Overhaul (1200h)</span>
          </div>
        </div>
      </div>

      <div style={{
        position: "relative",
        height: "200px",
        display: "flex",
        alignItems: "flex-end",
        gap: "2px",
        padding: "0 4px",
        backgroundColor: "white",
        borderRadius: "4px",
        border: "1px solid #E1E8ED"
      }}>
        {/* Capacity line */}
        <div
          style={{
            position: "absolute",
            left: 0,
            right: 0,
            bottom: `${(capacity / maxWorkload) * 100}%`,
            borderTop: "2px dashed #394B59",
            zIndex: 10,
          }}
        >
          <span style={{
            position: "absolute",
            right: "4px",
            top: "-16px",
            fontSize: "10px",
            color: "#394B59",
            fontWeight: 500,
          }}>
            Capacity: {capacity.toLocaleString()}
          </span>
        </div>

        {/* Stacked bars */}
        {stackedData.map((data, idx) => {
          const aHeight = (data["A-Check"] / maxWorkload) * 100;
          const bHeight = (data["B-Check"] / maxWorkload) * 100;
          const cHeight = (data["C-Check"] / maxWorkload) * 100;
          const dHeight = (data["D-Overhaul"] / maxWorkload) * 100;

          return (
            <div
              key={data.week}
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column-reverse",
                alignItems: "stretch",
                height: "100%",
              }}
              title={`Week ${data.week + 1}: A=${data["A-Check"]}h, B=${data["B-Check"]}h, C=${data["C-Check"]}h, D=${data["D-Overhaul"]}h, Total=${data.total}h`}
            >
              {data["A-Check"] > 0 && (
                <div style={{ height: `${aHeight}%`, backgroundColor: "#2965CC", minHeight: "2px" }} />
              )}
              {data["B-Check"] > 0 && (
                <div style={{ height: `${bHeight}%`, backgroundColor: "#29A634", minHeight: "2px" }} />
              )}
              {data["C-Check"] > 0 && (
                <div style={{ height: `${cHeight}%`, backgroundColor: "#D99E0B", minHeight: "2px" }} />
              )}
              {data["D-Overhaul"] > 0 && (
                <div style={{ height: `${dHeight}%`, backgroundColor: "#CD4246", minHeight: "2px" }} />
              )}
            </div>
          );
        })}
      </div>

      {/* X-axis labels */}
      <div style={{
        display: "flex",
        gap: "2px",
        padding: "4px 4px 0",
        fontSize: "9px",
        color: "#5F6B7C"
      }}>
        {stackedData.map((data, idx) => (
          <div key={data.week} style={{ flex: 1, textAlign: "center" }}>
            {(idx % Math.ceil(horizonWeeks / 13) === 0) ? `W${data.week + 1}` : ""}
          </div>
        ))}
      </div>
    </div>
  );
}

// ============================================================================
// 4. EVENT WINDOW VISUALIZATION - Shows target vs actual with tolerance bands
// ============================================================================

interface EventWindowProps {
  input: SolverInput;
  assignments: EventAssignment[];
  maxEvents?: number;
}

export function EventWindowVisualization({ input, assignments, maxEvents = 20 }: EventWindowProps) {
  const eventData = useMemo(() => {
    const eventMap = new Map(input.events.map(e => [e.id, e]));
    const assetMap = new Map(input.assets.map(a => [a.id, a]));

    return assignments
      .map(assignment => {
        const event = eventMap.get(assignment.eventId);
        if (!event) return null;

        const asset = assetMap.get(event.assetId);

        return {
          eventId: assignment.eventId,
          assetId: event.assetId,
          assetType: asset?.assetType || "Unknown",
          maintenanceType: event.maintenanceTypeId,
          earliest: event.earliestPeriod,
          target: event.targetPeriod,
          latest: event.latestPeriod,
          assigned: assignment.assignedPeriod,
          deviation: assignment.deviation,
          isOnTarget: Math.abs(assignment.deviation) <= 2,
        };
      })
      .filter(Boolean)
      .slice(0, maxEvents);
  }, [input, assignments, maxEvents]);

  const horizonWeeks = input.planningHorizonWeeks;

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
        <h4 style={{ margin: 0 }}>Scheduling Windows & Assignments</h4>
        <div style={{ display: "flex", gap: "16px", fontSize: "11px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div style={{ width: "20px", height: "8px", backgroundColor: "#E1E8ED", border: "1px solid #CED9E0" }} />
            <span>Allowed Window</span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div style={{ width: "8px", height: "8px", backgroundColor: "#394B59", borderRadius: "50%" }} />
            <span>Target</span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div style={{ width: "8px", height: "8px", backgroundColor: "#0D8050", borderRadius: "50%" }} />
            <span>Assigned</span>
          </div>
        </div>
      </div>

      <div style={{ maxHeight: "300px", overflowY: "auto" }}>
        {eventData.map((data, idx) => {
          if (!data) return null;

          const windowStart = (data.earliest / horizonWeeks) * 100;
          const windowWidth = ((data.latest - data.earliest + 1) / horizonWeeks) * 100;
          const targetPos = (data.target / horizonWeeks) * 100;
          const assignedPos = (data.assigned / horizonWeeks) * 100;

          return (
            <div
              key={data.eventId}
              style={{
                display: "flex",
                alignItems: "center",
                height: "28px",
                borderBottom: "1px solid #F5F8FA",
              }}
            >
              <div style={{ width: "100px", flexShrink: 0, fontSize: "10px" }}>
                <code style={{ color: data.assetType === "ALSTOM" ? "#2965CC" : "#29A634" }}>
                  {data.assetId}
                </code>
                <Tag minimal style={{ marginLeft: "4px", fontSize: "9px" }}>
                  {MAINTENANCE_LABELS[data.maintenanceType]}
                </Tag>
              </div>

              <div style={{ flex: 1, position: "relative", height: "100%", marginRight: "8px" }}>
                {/* Window band */}
                <div
                  style={{
                    position: "absolute",
                    left: `${windowStart}%`,
                    width: `${windowWidth}%`,
                    top: "8px",
                    height: "12px",
                    backgroundColor: "#E1E8ED",
                    borderRadius: "2px",
                  }}
                />

                {/* Target marker */}
                <div
                  style={{
                    position: "absolute",
                    left: `${targetPos}%`,
                    top: "6px",
                    width: "8px",
                    height: "16px",
                    marginLeft: "-4px",
                    backgroundColor: "#394B59",
                    borderRadius: "2px",
                    opacity: 0.5,
                  }}
                  title={`Target: Week ${data.target + 1}`}
                />

                {/* Assigned marker */}
                <div
                  style={{
                    position: "absolute",
                    left: `${assignedPos}%`,
                    top: "4px",
                    width: "12px",
                    height: "20px",
                    marginLeft: "-6px",
                    backgroundColor: data.isOnTarget ? "#0D8050" : "#BF7326",
                    borderRadius: "3px",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    color: "white",
                    fontSize: "8px",
                    fontWeight: 600,
                  }}
                  title={`Assigned: Week ${data.assigned + 1} (deviation: ${data.deviation >= 0 ? "+" : ""}${data.deviation})`}
                >
                  {data.assigned + 1}
                </div>
              </div>

              <div style={{ width: "60px", textAlign: "right", fontSize: "10px" }}>
                <span style={{
                  color: data.deviation === 0 ? "#0D8050" : Math.abs(data.deviation) <= 2 ? "#BF7326" : "#CD4246"
                }}>
                  {data.deviation >= 0 ? "+" : ""}{data.deviation}w
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {assignments.length > maxEvents && (
        <p style={{ textAlign: "center", color: "#8A9BA8", fontSize: "11px", marginTop: "8px" }}>
          Showing first {maxEvents} of {assignments.length} events
        </p>
      )}
    </div>
  );
}

// ============================================================================
// 5. SOLVER DIAGNOSTICS - Technical proof the solver actually ran
// ============================================================================

interface SolverDiagnosticsDisplayProps {
  output: SolverOutput;
  eventsCount: number;
  assetsCount: number;
}

export function SolverDiagnosticsDisplay({ output, eventsCount, assetsCount }: SolverDiagnosticsDisplayProps) {
  const { diagnostics } = output;

  return (
    <div style={{
      padding: "16px",
      backgroundColor: "#252A31",
      borderRadius: "8px",
      color: "#F5F8FA",
      fontFamily: "monospace",
      fontSize: "12px",
    }}>
      <div style={{ color: "#8A9BA8", marginBottom: "8px" }}>// Solver Execution Report</div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: "16px" }}>
        <div>
          <div style={{ color: "#72CA9B" }}>SOLVER</div>
          <div style={{ fontSize: "16px", fontWeight: 600 }}>{diagnostics.solverName}</div>
        </div>

        <div>
          <div style={{ color: "#72CA9B" }}>STATUS</div>
          <div style={{
            fontSize: "16px",
            fontWeight: 600,
            color: output.status === "OPTIMAL" ? "#72CA9B" : output.status === "FEASIBLE" ? "#FBD065" : "#FA999C"
          }}>
            {output.status}
          </div>
        </div>

        <div>
          <div style={{ color: "#8A9BA8" }}>solve_time</div>
          <div>{diagnostics.solveTimeMs.toFixed(2)} ms</div>
        </div>

        <div>
          <div style={{ color: "#8A9BA8" }}>iterations</div>
          <div>{diagnostics.iterations.toLocaleString()}</div>
        </div>

        <div>
          <div style={{ color: "#8A9BA8" }}>mip_gap</div>
          <div>{diagnostics.mipGap ? `${(diagnostics.mipGap * 100).toFixed(3)}%` : "N/A"}</div>
        </div>

        <div>
          <div style={{ color: "#8A9BA8" }}>node_count</div>
          <div>{diagnostics.nodeCount?.toLocaleString() || "N/A"}</div>
        </div>

        <div>
          <div style={{ color: "#8A9BA8" }}>events_scheduled</div>
          <div>{output.solution?.assignments.length || 0} / {eventsCount}</div>
        </div>

        <div>
          <div style={{ color: "#8A9BA8" }}>assets_covered</div>
          <div>{assetsCount} trains</div>
        </div>
      </div>

      {diagnostics.warnings && diagnostics.warnings.length > 0 && (
        <div style={{ marginTop: "12px", padding: "8px", backgroundColor: "#3D434A", borderRadius: "4px" }}>
          <div style={{ color: "#FBD065", marginBottom: "4px" }}>warnings:</div>
          {diagnostics.warnings.map((w, i) => (
            <div key={i} style={{ color: "#FA999C" }}>{w}</div>
          ))}
        </div>
      )}
    </div>
  );
}

