   206→export function generateBaselineWorkload(
   207→  events: SolverEvent[],
   208→  horizonWeeks: number,
   209→  capacity: number
   210→): PeriodWorkload[] {
   211→  const workloadByPeriod: number[] = new Array(horizonWeeks).fill(0);
   212→  const eventCountByPeriod: number[] = new Array(horizonWeeks).fill(0);
   213→
   214→  // Schedule each event at its target period (no optimization)
   215→  for (const event of events) {
   216→    const period = Math.min(Math.max(0, event.targetPeriod), horizonWeeks - 1);
   217→    workloadByPeriod[period] += event.manHours;
   218→    eventCountByPeriod[period] += 1;
   219→  }
   220→
   221→  return workloadByPeriod.map((manHours, period) => ({
   222→    period,
   223→    manHours,
   224→    eventCount: eventCountByPeriod[period],
   225→    utilization: capacity > 0 ? manHours / capacity : 0,
   226→  }));
   227→}
