   245→    const optimizedPeak = Math.max(...optimizedWorkload.map(p => p.manHours));
   246→    const peakReduction = ((baselinePeak - optimizedPeak) / baselinePeak) * 100;
   247→
   248→    const baselineViolations = baselineWorkload.filter(p => p.manHours > capacity).length;
   249→    const optimizedViolations = optimizedWorkload.filter(p => p.manHours > capacity).length;
   250→
   251→    const baselineHours = baselineWorkload.map(p => p.manHours);
   252→    const optimizedHours = optimizedWorkload.map(p => p.manHours);
   253→
   254→    const baselineAvg = baselineHours.reduce((a, b) => a + b, 0) / baselineHours.length;
   255→    const optimizedAvg = optimizedHours.reduce((a, b) => a + b, 0) / optimizedHours.length;
   256→
   257→    const baselineVariance = baselineHours.reduce((sum, h) => sum + Math.pow(h - baselineAvg, 2), 0) / baselineHours.length;
   258→    const optimizedVariance = optimizedHours.reduce((sum, h) => sum + Math.pow(h - optimizedAvg, 2), 0) / optimizedHours.length;
   259→
   260→    const varianceReduction = baselineVariance > 0
   261→      ? ((baselineVariance - optimizedVariance) / baselineVariance) * 100
   262→      : 0;
   263→
   264→    return {
