import { useMemo } from "react";
import { Tag, Intent } from "@blueprintjs/core";
import type { PeriodWorkload, SolverEvent } from "@uptime/types";

interface WorkloadChartProps {
  title: string;
  workloadProfile: PeriodWorkload[];
  capacity: number;
  showCapacityLine?: boolean;
  variant?: "before" | "after";
}

/**
 * Workload bar chart visualization
 * Replicates the style from the RFQ case study (Section 8)
 */
export function WorkloadChart({
  title,
  workloadProfile,
  capacity,
  showCapacityLine = true,
  variant = "after",
}: WorkloadChartProps) {
  const maxWorkload = useMemo(() => {
    const peak = Math.max(...workloadProfile.map((p) => p.manHours));
    return Math.max(peak, capacity) * 1.1; // 10% headroom
  }, [workloadProfile, capacity]);

  const stats = useMemo(() => {
    const hours = workloadProfile.map((p) => p.manHours);
    const peak = Math.max(...hours);
    const avg = hours.reduce((a, b) => a + b, 0) / hours.length;
    const variance = hours.reduce((sum, h) => sum + Math.pow(h - avg, 2), 0) / hours.length;
    const stdDev = Math.sqrt(variance);
    const cv = avg > 0 ? stdDev / avg : 0;
    const violations = hours.filter((h) => h > capacity).length;

    return { peak, avg, stdDev, cv, violations };
  }, [workloadProfile, capacity]);

  const barColor = variant === "before" ? "#CD4246" : "#238551";
  const barColorLight = variant === "before" ? "#FA999C" : "#72CA9B";

  return (
    <div style={{
      padding: "16px",
      backgroundColor: variant === "before" ? "#FFF5F5" : "#F0FFF4",
      borderRadius: "8px",
      border: `1px solid ${variant === "before" ? "#FFCCCB" : "#B7EB8F"}`
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" }}>
        <h4 style={{ margin: 0, color: variant === "before" ? "#A82A2A" : "#0D8050" }}>
          {title}
        </h4>
        <div style={{ display: "flex", gap: "8px" }}>
          <Tag
            intent={stats.violations > 0 ? Intent.DANGER : Intent.SUCCESS}
            minimal
          >
            {stats.violations > 0 ? `${stats.violations} violations` : "No violations"}
          </Tag>
          <Tag minimal>
            Peak: {stats.peak.toLocaleString()} hrs
          </Tag>
        </div>
      </div>

      {/* Chart area */}
      <div style={{
        position: "relative",
        height: "200px",
        display: "flex",
        alignItems: "flex-end",
        gap: "2px",
        padding: "0 4px",
        backgroundColor: "white",
        borderRadius: "4px",
        border: "1px solid #E1E8ED"
      }}>
        {/* Capacity line */}
        {showCapacityLine && (
          <div
            style={{
              position: "absolute",
              left: 0,
              right: 0,
              bottom: `${(capacity / maxWorkload) * 100}%`,
              borderTop: "2px dashed #394B59",
              zIndex: 10,
            }}
          >
            <span style={{
              position: "absolute",
              right: "4px",
              top: "-20px",
              fontSize: "10px",
              color: "#394B59",
              fontWeight: 500,
            }}>
              Capacity: {capacity.toLocaleString()}
            </span>
          </div>
        )}

        {/* Bars */}
        {workloadProfile.map((period, idx) => {
          const heightPercent = (period.manHours / maxWorkload) * 100;
          const isOverCapacity = period.manHours > capacity;

          return (
            <div
              key={period.period}
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                height: "100%",
                justifyContent: "flex-end",
              }}
            >
              <div
                style={{
                  width: "100%",
                  height: `${heightPercent}%`,
                  backgroundColor: isOverCapacity ? "#CD4246" : barColor,
                  borderRadius: "2px 2px 0 0",
                  minHeight: "4px",
                  transition: "height 0.3s ease",
                  position: "relative",
                }}
                title={`Week ${period.period + 1}: ${period.manHours.toLocaleString()} man-hours (${period.eventCount} events)`}
              >
                {isOverCapacity && (
                  <div style={{
                    position: "absolute",
                    top: "-16px",
                    left: "50%",
                    transform: "translateX(-50%)",
                    fontSize: "10px",
                    color: "#CD4246",
                    fontWeight: "bold",
                  }}>
                    !
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* X-axis labels */}
      <div style={{
        display: "flex",
        gap: "2px",
        padding: "4px 4px 0",
        fontSize: "9px",
        color: "#5F6B7C"
      }}>
        {workloadProfile.map((period, idx) => (
          <div key={period.period} style={{ flex: 1, textAlign: "center" }}>
            {(idx % Math.ceil(workloadProfile.length / 13) === 0) ? `W${period.period + 1}` : ""}
          </div>
        ))}
      </div>

      {/* Stats row */}
      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(4, 1fr)",
        gap: "8px",
        marginTop: "12px",
        padding: "8px",
        backgroundColor: "white",
        borderRadius: "4px",
        fontSize: "12px"
      }}>
        <div>
          <div style={{ color: "#5F6B7C" }}>Peak</div>
          <div style={{ fontWeight: 600, color: stats.peak > capacity ? "#CD4246" : "#182026" }}>
            {stats.peak.toLocaleString()}
          </div>
        </div>
        <div>
          <div style={{ color: "#5F6B7C" }}>Average</div>
          <div style={{ fontWeight: 600 }}>{Math.round(stats.avg).toLocaleString()}</div>
        </div>
        <div>
          <div style={{ color: "#5F6B7C" }}>Std Dev</div>
          <div style={{ fontWeight: 600 }}>{Math.round(stats.stdDev).toLocaleString()}</div>
        </div>
        <div>
          <div style={{ color: "#5F6B7C" }}>CV</div>
          <div style={{ fontWeight: 600 }}>{(stats.cv * 100).toFixed(1)}%</div>
        </div>
      </div>
    </div>
  );
}

/**
 * Generate "before" workload - what happens without optimization
 * Events scheduled at their target period without balancing
 */
export function generateBaselineWorkload(
  events: SolverEvent[],
  horizonWeeks: number,
  capacity: number
): PeriodWorkload[] {
  const workloadByPeriod: number[] = new Array(horizonWeeks).fill(0);
  const eventCountByPeriod: number[] = new Array(horizonWeeks).fill(0);

  // Schedule each event at its target period (no optimization)
  for (const event of events) {
    const period = Math.min(Math.max(0, event.targetPeriod), horizonWeeks - 1);
    workloadByPeriod[period] += event.manHours;
    eventCountByPeriod[period] += 1;
  }

  return workloadByPeriod.map((manHours, period) => ({
    period,
    manHours,
    eventCount: eventCountByPeriod[period],
    utilization: capacity > 0 ? manHours / capacity : 0,
  }));
}

/**
 * Comparison component showing before/after side by side
 */
interface WorkloadComparisonProps {
  baselineWorkload: PeriodWorkload[];
  optimizedWorkload: PeriodWorkload[];
  capacity: number;
}

export function WorkloadComparison({
  baselineWorkload,
  optimizedWorkload,
  capacity,
}: WorkloadComparisonProps) {
  const improvement = useMemo(() => {
    const baselinePeak = Math.max(...baselineWorkload.map(p => p.manHours));
    const optimizedPeak = Math.max(...optimizedWorkload.map(p => p.manHours));
    const peakReduction = ((baselinePeak - optimizedPeak) / baselinePeak) * 100;

    const baselineViolations = baselineWorkload.filter(p => p.manHours > capacity).length;
    const optimizedViolations = optimizedWorkload.filter(p => p.manHours > capacity).length;

    const baselineHours = baselineWorkload.map(p => p.manHours);
    const optimizedHours = optimizedWorkload.map(p => p.manHours);

    const baselineAvg = baselineHours.reduce((a, b) => a + b, 0) / baselineHours.length;
    const optimizedAvg = optimizedHours.reduce((a, b) => a + b, 0) / optimizedHours.length;

    const baselineVariance = baselineHours.reduce((sum, h) => sum + Math.pow(h - baselineAvg, 2), 0) / baselineHours.length;
    const optimizedVariance = optimizedHours.reduce((sum, h) => sum + Math.pow(h - optimizedAvg, 2), 0) / optimizedHours.length;

    const varianceReduction = baselineVariance > 0
      ? ((baselineVariance - optimizedVariance) / baselineVariance) * 100
      : 0;

    return {
      baselinePeak,
      optimizedPeak,
      peakReduction,
      baselineViolations,
      optimizedViolations,
      violationsFixed: baselineViolations - optimizedViolations,
      varianceReduction,
    };
  }, [baselineWorkload, optimizedWorkload, capacity]);

  return (
    <div>
      {/* Impact Summary */}
      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(3, 1fr)",
        gap: "16px",
        marginBottom: "24px",
        padding: "16px",
        backgroundColor: "#E1E8ED",
        borderRadius: "8px",
      }}>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "28px", fontWeight: 700, color: "#0D8050" }}>
            -{improvement.peakReduction.toFixed(0)}%
          </div>
          <div style={{ fontSize: "12px", color: "#5F6B7C" }}>Peak Reduction</div>
          <div style={{ fontSize: "11px", color: "#8A9BA8" }}>
            {improvement.baselinePeak.toLocaleString()} → {improvement.optimizedPeak.toLocaleString()}
          </div>
        </div>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "28px", fontWeight: 700, color: improvement.optimizedViolations === 0 ? "#0D8050" : "#C23030" }}>
            {improvement.violationsFixed}
          </div>
          <div style={{ fontSize: "12px", color: "#5F6B7C" }}>Violations Fixed</div>
          <div style={{ fontSize: "11px", color: "#8A9BA8" }}>
            {improvement.baselineViolations} → {improvement.optimizedViolations}
          </div>
        </div>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "28px", fontWeight: 700, color: "#0D8050" }}>
            -{improvement.varianceReduction.toFixed(0)}%
          </div>
          <div style={{ fontSize: "12px", color: "#5F6B7C" }}>Variance Reduction</div>
          <div style={{ fontSize: "11px", color: "#8A9BA8" }}>Smoother workload</div>
        </div>
      </div>

      {/* Side by side charts */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px" }}>
        <WorkloadChart
          title="Without Optimization"
          workloadProfile={baselineWorkload}
          capacity={capacity}
          variant="before"
        />
        <WorkloadChart
          title="With MMS Optimization"
          workloadProfile={optimizedWorkload}
          capacity={capacity}
          variant="after"
        />
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import {
  Card,
  Elevation,
  Tag,
  Intent,
  Icon,
  Spinner,
  Callout,
} from "@blueprintjs/core";
import { getFleetSummary, type FleetSummary } from "../lib/api";
import { getFleetSummary as getFallbackSummary, generateFleet, TOTAL_FLEET } from "../lib/demo-data";

export function Dashboard() {
  const [summary, setSummary] = useState<FleetSummary | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isLiveData, setIsLiveData] = useState(false);

  useEffect(() => {
    async function loadSummary() {
      try {
        const data = await getFleetSummary();
        setSummary(data);
        setIsLiveData(true);
      } catch (err) {
        // Fallback to demo data if API is not available
        console.warn("API not available, using demo data:", err);
        const fleet = generateFleet(TOTAL_FLEET);
        const fallback = getFallbackSummary(fleet);
        setSummary({
          total: fallback.total,
          alstomCount: fallback.alstomCount,
          kinkiCount: fallback.kinkiCount,
          avgMileage: fallback.avgMileage,
          alstomAvgMileage: fallback.alstomAvgMileage,
          kinkiAvgMileage: fallback.kinkiAvgMileage,
          operational: fallback.total,
          inMaintenance: 0,
        });
        setIsLiveData(false);
        setError("Using demo data - API not connected");
      } finally {
        setLoading(false);
      }
    }

    loadSummary();
  }, []);

  if (loading) {
    return (
      <div style={{ textAlign: "center", padding: "40px" }}>
        <Spinner size={40} />
        <p style={{ color: "#5f6b7c", marginTop: "16px" }}>Loading fleet data...</p>
      </div>
    );
  }

  if (!summary) {
    return (
      <Callout intent={Intent.DANGER} title="Failed to load data">
        Unable to load fleet summary.
      </Callout>
    );
  }

  return (
    <div>
      {error && (
        <Callout intent={Intent.WARNING} style={{ marginBottom: "16px" }}>
          {error}
        </Callout>
      )}

      {isLiveData && (
        <Callout intent={Intent.SUCCESS} icon="database" style={{ marginBottom: "16px" }}>
          Connected to database - showing live data
        </Callout>
      )}

      <div className="card-grid">
        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Icon icon="train" size={20} />
            <span style={{ fontWeight: 500 }}>Total Fleet</span>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.total}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>
            {summary.operational} operational, {summary.inMaintenance} in maintenance
          </div>
        </Card>

        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Icon icon="drive-time" size={20} />
            <span style={{ fontWeight: 500 }}>Avg Mileage</span>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.avgMileage.toLocaleString()}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>kilometers</div>
        </Card>

        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Tag intent={Intent.PRIMARY}>Alstom</Tag>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.alstomCount}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>
            Avg: {summary.alstomAvgMileage.toLocaleString()} km
          </div>
        </Card>

        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Tag intent={Intent.SUCCESS}>Kinki Sharyo</Tag>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.kinkiCount}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>
            Avg: {summary.kinkiAvgMileage.toLocaleString()} km
          </div>
        </Card>
      </div>

      <Card elevation={Elevation.TWO}>
        <h3 style={{ marginTop: 0 }}>Quick Actions</h3>
        <p style={{ color: "#5f6b7c" }}>
          Use the sidebar to navigate to different sections:
        </p>
        <ul style={{ color: "#5f6b7c", lineHeight: 1.8 }}>
          <li>
            <strong>Fleet</strong> - View all {summary.total} trains and their current status
          </li>
          <li>
            <strong>Schedule</strong> - View upcoming maintenance events
          </li>
          <li>
            <strong>Calendar</strong> - Visual calendar of scheduled maintenance
          </li>
          <li>
            <strong>What-If Simulator</strong> - Test different scheduling scenarios
          </li>
        </ul>
      </Card>
    </div>
  );
}

