import { useState, useCallback, useMemo } from "react";
import {
  Card,
  Elevation,
  Button,
  Intent,
  FormGroup,
  Slider,
  HTMLSelect,
  Spinner,
  Callout,
  Tag,
  Divider,
  HTMLTable,
  Tabs,
  Tab,
} from "@blueprintjs/core";
import type { SolverOutput, SolverInput } from "@uptime/types";
import { createSolverInput, maintenanceTypes } from "../lib/demo-data";
import { solveSchedule } from "../lib/api";
import { WorkloadComparison, generateBaselineWorkload } from "./WorkloadChart";
import {
  ScheduleGantt,
  ConstraintSatisfaction,
  WorkloadByType,
  EventWindowVisualization,
  SolverDiagnosticsDisplay,
} from "./AdvancedVisualizations";

export function WhatIfSimulator() {
  const [isRunning, setIsRunning] = useState(false);
  const [result, setResult] = useState<SolverOutput | null>(null);
  const [solverInput, setSolverInput] = useState<SolverInput | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Form state
  const [capacity, setCapacity] = useState(5200);
  const [horizon, setHorizon] = useState(13);
  const [fleetSize, setFleetSize] = useState(128);

  const runSimulation = useCallback(async () => {
    setIsRunning(true);
    setError(null);
    setResult(null);

    try {
      const input = createSolverInput(fleetSize, horizon, capacity);
      setSolverInput(input);
      const output = await solveSchedule(input);
      setResult(output);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Unknown error");
    } finally {
      setIsRunning(false);
    }
  }, [capacity, horizon, fleetSize]);

  const resetForm = () => {
    setCapacity(5200);
    setHorizon(13);
    setFleetSize(128);
    setResult(null);
    setSolverInput(null);
    setError(null);
  };

  // Generate baseline workload (without optimization)
  const baselineWorkload = useMemo(() => {
    if (!solverInput) return null;
    return generateBaselineWorkload(solverInput.events, horizon, capacity);
  }, [solverInput, horizon, capacity]);

  // Get event details for the schedule table
  const scheduleDetails = useMemo(() => {
    if (!result?.solution?.assignments || !solverInput) return [];

    const eventMap = new Map(solverInput.events.map(e => [e.id, e]));
    const assetMap = new Map(solverInput.assets.map(a => [a.id, a]));
    const mtMap = new Map(maintenanceTypes.map(m => [m.id, m]));

    return result.solution.assignments
      .map(assignment => {
        const event = eventMap.get(assignment.eventId);
        if (!event) return null;

        const asset = assetMap.get(event.assetId);
        const mt = mtMap.get(event.maintenanceTypeId);

        return {
          eventId: assignment.eventId,
          assetId: event.assetId,
          assetType: asset?.assetType || "Unknown",
          maintenanceType: mt?.name || event.maintenanceTypeId,
          maintenanceLevel: mt?.level || "?",
          assignedWeek: assignment.assignedPeriod + 1,
          targetWeek: event.targetPeriod + 1,
          deviation: assignment.deviation,
          manHours: event.manHours,
          withinTolerance: Math.abs(assignment.deviation) <= 2,
        };
      })
      .filter(Boolean)
      .sort((a, b) => a!.assignedWeek - b!.assignedWeek);
  }, [result, solverInput]);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
      {/* Configuration Panel */}
      <Card elevation={Elevation.TWO}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <h3 style={{ margin: 0 }}>Scenario Configuration</h3>
          <Tag minimal>Dubai Metro Fleet</Tag>
        </div>

        <Divider style={{ margin: "16px 0" }} />

        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "24px" }}>
          <FormGroup label="Planning Horizon" labelInfo="(weeks)">
            <HTMLSelect
              value={horizon}
              onChange={(e) => setHorizon(parseInt(e.target.value))}
              fill
            >
              <option value={13}>13 weeks (Quarter)</option>
              <option value={26}>26 weeks (Half Year)</option>
              <option value={52}>52 weeks (Full Year)</option>
            </HTMLSelect>
          </FormGroup>

          <FormGroup
            label="Weekly Capacity"
            labelInfo={`${capacity.toLocaleString()} man-hours`}
          >
            <Slider
              min={3000}
              max={8000}
              stepSize={100}
              value={capacity}
              onChange={setCapacity}
              labelStepSize={1000}
            />
          </FormGroup>

          <FormGroup label="Fleet Size">
            <HTMLSelect
              value={fleetSize}
              onChange={(e) => setFleetSize(parseInt(e.target.value))}
              fill
            >
              <option value={128}>Full Fleet (128 trains)</option>
              <option value={79}>Alstom Only (79 trains)</option>
              <option value={49}>Kinki Only (49 trains)</option>
              <option value={20}>Test Fleet (20 trains)</option>
            </HTMLSelect>
          </FormGroup>
        </div>

        <div style={{ display: "flex", gap: "8px", marginTop: "16px" }}>
          <Button onClick={resetForm} disabled={isRunning}>
            Reset
          </Button>
          <Button
            intent={Intent.PRIMARY}
            loading={isRunning}
            onClick={runSimulation}
            icon="play"
            large
          >
            {isRunning ? "Optimizing..." : "Run Optimization"}
          </Button>
        </div>
      </Card>

      {/* Loading State */}
      {isRunning && (
        <Card elevation={Elevation.TWO}>
          <div style={{ textAlign: "center", padding: "40px 0" }}>
            <Spinner size={50} />
            <p style={{ color: "#5f6b7c", marginTop: "16px", marginBottom: "8px" }}>
              Running HiGHS MIP Solver...
            </p>
            <p style={{ color: "#8a9ba8", fontSize: "12px" }}>
              Optimizing schedule for {fleetSize} trains over {horizon} weeks
            </p>
          </div>
        </Card>
      )}

      {/* Error State */}
      {error && (
        <Callout intent={Intent.DANGER} title="Solver Error">
          {error}
        </Callout>
      )}

      {/* Results */}
      {result && !isRunning && baselineWorkload && result.solution && solverInput && (
        <>
          {/* Status Banner */}
          <Callout
            intent={
              result.status === "OPTIMAL"
                ? Intent.SUCCESS
                : result.status === "FEASIBLE"
                ? Intent.PRIMARY
                : Intent.WARNING
            }
            icon={result.status === "OPTIMAL" ? "tick-circle" : "info-sign"}
          >
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <strong>{result.status}</strong> solution found
                {" - "}
                {result.solution.assignments.length} maintenance events scheduled across {horizon} weeks
              </div>
              <div style={{ display: "flex", gap: "16px", fontSize: "12px" }}>
                <span>Solve time: <strong>{result.diagnostics.solveTimeMs.toFixed(0)}ms</strong></span>
                <span>Iterations: <strong>{result.diagnostics.iterations.toLocaleString()}</strong></span>
              </div>
            </div>
          </Callout>

          {/* Key Metrics - Always visible */}
          {result.metrics && (
            <Card elevation={Elevation.TWO}>
              <h3 style={{ marginTop: 0 }}>Optimization Results</h3>

              <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "24px", marginTop: "16px" }}>
                <div style={{ textAlign: "center", padding: "16px", backgroundColor: "#F5F8FA", borderRadius: "8px" }}>
                  <div style={{ fontSize: "32px", fontWeight: 700, color: "#182026" }}>
                    {result.metrics.peakWorkload.toLocaleString()}
                  </div>
                  <div style={{ color: "#5F6B7C", fontSize: "12px" }}>Peak Workload (man-hrs)</div>
                  <Tag
                    minimal
                    intent={result.metrics.peakWorkload <= capacity ? Intent.SUCCESS : Intent.DANGER}
                    style={{ marginTop: "8px" }}
                  >
                    {result.metrics.peakWorkload <= capacity ? "Within Capacity" : "Over Capacity"}
                  </Tag>
                </div>

                <div style={{ textAlign: "center", padding: "16px", backgroundColor: "#F5F8FA", borderRadius: "8px" }}>
                  <div style={{ fontSize: "32px", fontWeight: 700, color: "#182026" }}>
                    {(result.metrics.complianceRate * 100).toFixed(0)}%
                  </div>
                  <div style={{ color: "#5F6B7C", fontSize: "12px" }}>Compliance Rate</div>
                  <Tag
                    minimal
                    intent={result.metrics.complianceRate >= 0.95 ? Intent.SUCCESS : Intent.WARNING}
                    style={{ marginTop: "8px" }}
                  >
                    Events on schedule
                  </Tag>
                </div>

                <div style={{ textAlign: "center", padding: "16px", backgroundColor: "#F5F8FA", borderRadius: "8px" }}>
                  <div style={{ fontSize: "32px", fontWeight: 700, color: "#182026" }}>
                    {(result.metrics.workloadCv * 100).toFixed(0)}%
                  </div>
                  <div style={{ color: "#5F6B7C", fontSize: "12px" }}>Workload Variance (CV)</div>
                  <Tag
                    minimal
                    intent={result.metrics.workloadCv < 0.3 ? Intent.SUCCESS : Intent.WARNING}
                    style={{ marginTop: "8px" }}
                  >
                    {result.metrics.workloadCv < 0.3 ? "Well Balanced" : "Moderate Variance"}
                  </Tag>
                </div>

                <div style={{ textAlign: "center", padding: "16px", backgroundColor: "#F5F8FA", borderRadius: "8px" }}>
                  <div style={{ fontSize: "32px", fontWeight: 700, color: "#182026" }}>
                    ${(result.metrics.totalCost / 1000).toFixed(0)}K
                  </div>
                  <div style={{ color: "#5F6B7C", fontSize: "12px" }}>Estimated Cost</div>
                  <Tag minimal style={{ marginTop: "8px" }}>
                    {horizon} week period
                  </Tag>
                </div>
              </div>
            </Card>
          )}

          {/* Advanced Visualizations in Tabs */}
          <Card elevation={Elevation.TWO}>
            <Tabs id="result-tabs" large>
              <Tab
                id="comparison"
                title="Before/After"
                panel={
                  <div style={{ paddingTop: "16px" }}>
                    <p style={{ color: "#5f6b7c", marginBottom: "24px" }}>
                      Compare workload distribution before optimization (events at target dates) vs after
                      optimization (events redistributed to level workload).
                    </p>
                    <WorkloadComparison
                      baselineWorkload={baselineWorkload}
                      optimizedWorkload={result.solution.workloadProfile}
                      capacity={capacity}
                    />
                  </div>
                }
              />

              <Tab
                id="timeline"
                title="Schedule Timeline"
                panel={
                  <div style={{ paddingTop: "16px" }}>
                    <ScheduleGantt
                      input={solverInput}
                      assignments={result.solution.assignments}
                      horizonWeeks={horizon}
                      maxTrains={40}
                    />
                  </div>
                }
              />

              <Tab
                id="workload-type"
                title="By Maintenance Type"
                panel={
                  <div style={{ paddingTop: "16px" }}>
                    <WorkloadByType
                      input={solverInput}
                      assignments={result.solution.assignments}
                      horizonWeeks={horizon}
                      capacity={capacity}
                    />
                  </div>
                }
              />

              <Tab
                id="windows"
                title="Scheduling Windows"
                panel={
                  <div style={{ paddingTop: "16px" }}>
                    <p style={{ color: "#5f6b7c", marginBottom: "16px" }}>
                      Each event has an allowed window (earliest to latest) and a target date.
                      The solver assigns each event within its window while balancing overall workload.
                    </p>
                    <EventWindowVisualization
                      input={solverInput}
                      assignments={result.solution.assignments}
                      maxEvents={30}
                    />
                  </div>
                }
              />

              <Tab
                id="constraints"
                title="Constraint Proof"
                panel={
                  <div style={{ paddingTop: "16px" }}>
                    <ConstraintSatisfaction
                      input={solverInput}
                      output={result}
                    />
                  </div>
                }
              />

              <Tab
                id="solver"
                title="Solver Details"
                panel={
                  <div style={{ paddingTop: "16px" }}>
                    <p style={{ color: "#5f6b7c", marginBottom: "16px" }}>
                      Technical details from the HiGHS Mixed-Integer Programming solver execution.
                    </p>
                    <SolverDiagnosticsDisplay
                      output={result}
                      eventsCount={solverInput.events.length}
                      assetsCount={solverInput.assets.length}
                    />
                  </div>
                }
              />

              <Tab
                id="table"
                title="Event Table"
                panel={
                  <div style={{ paddingTop: "16px" }}>
                    <div style={{ maxHeight: "400px", overflowY: "auto" }}>
                      <HTMLTable striped compact style={{ width: "100%" }}>
                        <thead>
                          <tr>
                            <th>Train</th>
                            <th>Fleet</th>
                            <th>Maintenance</th>
                            <th>Scheduled Week</th>
                            <th>Target Week</th>
                            <th>Deviation</th>
                            <th>Man-Hours</th>
                            <th>Status</th>
                          </tr>
                        </thead>
                        <tbody>
                          {scheduleDetails.slice(0, 50).map((event, idx) => (
                            <tr key={event!.eventId}>
                              <td>
                                <code>{event!.assetId}</code>
                              </td>
                              <td>
                                <Tag minimal intent={event!.assetType === "ALSTOM" ? Intent.PRIMARY : Intent.SUCCESS}>
                                  {event!.assetType}
                                </Tag>
                              </td>
                              <td>
                                <Tag minimal>{event!.maintenanceLevel}</Tag>
                                {" "}{event!.maintenanceType}
                              </td>
                              <td style={{ fontWeight: 600 }}>Week {event!.assignedWeek}</td>
                              <td style={{ color: "#5F6B7C" }}>Week {event!.targetWeek}</td>
                              <td>
                                <span style={{
                                  color: event!.deviation === 0 ? "#0D8050" :
                                         Math.abs(event!.deviation) <= 2 ? "#BF7326" : "#C23030"
                                }}>
                                  {event!.deviation > 0 ? "+" : ""}{event!.deviation} weeks
                                </span>
                              </td>
                              <td>{event!.manHours}</td>
                              <td>
                                <Tag
                                  minimal
                                  intent={event!.withinTolerance ? Intent.SUCCESS : Intent.WARNING}
                                >
                                  {event!.withinTolerance ? "On Time" : "Adjusted"}
                                </Tag>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </HTMLTable>
                      {scheduleDetails.length > 50 && (
                        <p style={{ textAlign: "center", color: "#5F6B7C", padding: "8px" }}>
                          Showing first 50 of {scheduleDetails.length} events
                        </p>
                      )}
                    </div>
                  </div>
                }
              />
            </Tabs>
          </Card>
        </>
      )}

      {/* Empty State */}
      {!isRunning && !error && !result && (
        <Card elevation={Elevation.ONE}>
          <div style={{ textAlign: "center", padding: "60px 40px", color: "#5f6b7c" }}>
            <div style={{ fontSize: "48px", marginBottom: "16px" }}>
              <span role="img" aria-label="train">🚇</span>
            </div>
            <h3 style={{ color: "#182026", marginBottom: "8px" }}>
              Ready to Optimize
            </h3>
            <p style={{ maxWidth: "400px", margin: "0 auto" }}>
              Configure the scenario parameters above and click "Run Optimization"
              to generate an optimized maintenance schedule for the Dubai Metro fleet.
            </p>
          </div>
        </Card>
      )}
    </div>
  );
}

