import { useState, useMemo } from "react";
import {
  Card,
  Elevation,
  Button,
  Tag,
  Intent,
  ProgressBar,
  Dialog,
  HTMLTable,
} from "@blueprintjs/core";
import { generateFleet, generateEvents, maintenanceTypes, TOTAL_FLEET } from "../lib/demo-data";
import type { SolverEvent } from "@uptime/types";

const typeColors: Record<string, Intent> = {
  "mt-a": Intent.SUCCESS,
  "mt-b": Intent.WARNING,
  "mt-c": Intent.DANGER,
  "mt-d": Intent.PRIMARY,
};

interface WeekData {
  weekNumber: number;
  startDate: Date;
  totalManHours: number;
  eventCount: number;
  events: SolverEvent[];
}

export function CalendarView() {
  const [currentMonth, setCurrentMonth] = useState(new Date(2025, 0, 1));
  const [selectedWeek, setSelectedWeek] = useState<WeekData | null>(null);
  const weeklyCapacity = 5200;

  const events = useMemo(() => {
    const fleet = generateFleet(TOTAL_FLEET);
    return generateEvents(fleet, 52);
  }, []);

  const eventsByWeek = useMemo(() => {
    const byWeek = new Map<number, SolverEvent[]>();
    for (const event of events) {
      const week = event.targetPeriod;
      if (!byWeek.has(week)) {
        byWeek.set(week, []);
      }
      byWeek.get(week)!.push(event);
    }
    return byWeek;
  }, [events]);

  const weeksInView = useMemo(() => {
    const weeks: WeekData[] = [];
    const year = currentMonth.getFullYear();
    const month = currentMonth.getMonth();
    const firstDay = new Date(year, month, 1);
    const startWeek = Math.floor(
      (firstDay.getTime() - new Date(year, 0, 1).getTime()) / (7 * 24 * 60 * 60 * 1000)
    );
    const lastDay = new Date(year, month + 1, 0);
    const endWeek = Math.floor(
      (lastDay.getTime() - new Date(year, 0, 1).getTime()) / (7 * 24 * 60 * 60 * 1000)
    );

    for (let w = startWeek; w <= endWeek && w < 52; w++) {
      const weekEvents = eventsByWeek.get(w) || [];
      const startDate = new Date(year, 0, 1 + w * 7);
      weeks.push({
        weekNumber: w + 1,
        startDate,
        totalManHours: weekEvents.reduce((sum, e) => sum + e.manHours, 0),
        eventCount: weekEvents.length,
        events: weekEvents,
      });
    }
    return weeks;
  }, [currentMonth, eventsByWeek]);

  const previousMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1));
  };

  const nextMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1));
  };

  const monthName = currentMonth.toLocaleDateString("en-US", {
    month: "long",
    year: "numeric",
  });

  const getMaintenanceType = (id: string) => {
    return maintenanceTypes.find((mt) => mt.id === id);
  };

  return (
    <div>
      <Card elevation={Elevation.ONE} style={{ marginBottom: "16px" }}>
        <div style={{ display: "flex", gap: "24px", alignItems: "center" }}>
          <span style={{ fontWeight: 500 }}>Legend:</span>
          {maintenanceTypes.map((mt) => (
            <div key={mt.id} style={{ display: "flex", alignItems: "center", gap: "8px" }}>
              <Tag intent={typeColors[mt.id]}>{mt.name}</Tag>
            </div>
          ))}
        </div>
      </Card>

      <Card elevation={Elevation.TWO}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "24px" }}>
          <h3 style={{ margin: 0 }}>Weekly Schedule</h3>
          <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
            <Button icon="chevron-left" minimal onClick={previousMonth} />
            <span style={{ minWidth: "150px", textAlign: "center", fontWeight: 500 }}>
              {monthName}
            </span>
            <Button icon="chevron-right" minimal onClick={nextMonth} />
          </div>
        </div>

        {weeksInView.map((week) => {
          const utilization = week.totalManHours / weeklyCapacity;
          return (
            <div
              key={week.weekNumber}
              onClick={() => setSelectedWeek(week)}
              style={{
                padding: "12px 16px",
                border: "1px solid #e1e8ed",
                borderRadius: "6px",
                marginBottom: "8px",
                cursor: "pointer",
                transition: "background-color 0.2s",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = "#f5f8fa")}
              onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = "transparent")}
            >
              <div style={{ display: "grid", gridTemplateColumns: "100px 150px 1fr 100px", gap: "16px", alignItems: "center" }}>
                <strong>Week {week.weekNumber}</strong>
                <span style={{ color: "#5f6b7c" }}>
                  {week.startDate.toLocaleDateString("en-US", { month: "short", day: "numeric" })}
                </span>
                <div>
                  <ProgressBar
                    value={Math.min(utilization, 1)}
                    intent={
                      utilization > 0.9
                        ? Intent.DANGER
                        : utilization > 0.7
                        ? Intent.WARNING
                        : Intent.SUCCESS
                    }
                    stripes={false}
                  />
                  <div style={{ fontSize: "11px", color: "#5f6b7c", marginTop: "4px" }}>
                    {week.totalManHours.toLocaleString()} / {weeklyCapacity.toLocaleString()} man-hours
                  </div>
                </div>
                <div style={{ display: "flex", gap: "4px" }}>
                  {Object.entries(typeColors).map(([typeId, intent]) => {
                    const count = week.events.filter((e) => e.maintenanceTypeId === typeId).length;
                    if (count === 0) return null;
                    return (
                      <Tag key={typeId} intent={intent} minimal round>
                        {count}
                      </Tag>
                    );
                  })}
                </div>
              </div>
            </div>
          );
        })}
      </Card>

      <Dialog
        isOpen={selectedWeek !== null}
        onClose={() => setSelectedWeek(null)}
        title={selectedWeek ? `Week ${selectedWeek.weekNumber} - ${selectedWeek.eventCount} Events` : ""}
        style={{ width: "700px" }}
      >
        <div style={{ padding: "20px" }}>
          {selectedWeek && (
            <>
              <p>
                <strong>Total Man-Hours:</strong> {selectedWeek.totalManHours.toLocaleString()}
              </p>
              <HTMLTable striped style={{ width: "100%" }}>
                <thead>
                  <tr>
                    <th>Train</th>
                    <th>Type</th>
                    <th>Man-Hours</th>
                    <th>Fleet</th>
                  </tr>
                </thead>
                <tbody>
                  {selectedWeek.events.map((event) => {
                    const mt = getMaintenanceType(event.maintenanceTypeId);
                    return (
                      <tr key={event.id}>
                        <td><strong>{event.assetId}</strong></td>
                        <td>
                          <Tag intent={typeColors[event.maintenanceTypeId]}>
                            {mt?.name}
                          </Tag>
                        </td>
                        <td>{event.manHours}h</td>
                        <td>{event.assetId.startsWith("ALT") ? "Alstom" : "Kinki Sharyo"}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </HTMLTable>
            </>
          )}
        </div>
      </Dialog>
    </div>
  );
}

