/**
 * Schedule Types - Master Plan and scheduling structures
 */

import type { MaintenanceEvent } from './maintenance';

export interface SchedulePeriod {
  weekNumber: number;
  year: number;
  startDate: string;
  endDate: string;
  events: MaintenanceEvent[];
  totalManHours: number;
  capacityManHours: number;
  utilizationRate: number; // 0-1
}

export interface MasterPlan {
  id: string;
  name: string;
  description?: string;
  version: number;
  status: MasterPlanStatus;

  // Planning horizon
  startWeek: number;
  startYear: number;
  endWeek: number;
  endYear: number;
  totalWeeks: number;

  // Content
  periods: SchedulePeriod[];
  events: MaintenanceEvent[];

  // Metrics
  metrics: ScheduleMetrics;

  // Metadata
  createdAt: string;
  updatedAt: string;
  createdBy?: string;
}

export type MasterPlanStatus =
  | 'DRAFT'
  | 'PENDING_APPROVAL'
  | 'APPROVED'
  | 'ACTIVE'
  | 'SUPERSEDED'
  | 'ARCHIVED';

export interface ScheduleMetrics {
  // Workload
  peakWorkloadManHours: number;
  averageWorkloadManHours: number;
  workloadVariance: number;
  workloadCV: number; // Coefficient of variation

  // Utilization
  averageUtilization: number;
  peakUtilization: number;
  overCapacityPeriods: number;

  // Compliance
  eventsOnTarget: number;
  eventsEarly: number;
  eventsLate: number;
  complianceRate: number;

  // Cost
  totalEstimatedCost: number;
  laborCost: number;
  partsCost: number;
}

export interface WorkloadProfile {
  weekNumber: number;
  year: number;
  manHours: number;
  capacity: number;
  utilization: number;
  eventCount: number;
  eventsByLevel: Record<string, number>;
}

export interface ResourceAllocation {
  periodId: string;
  resourceType: string;
  allocated: number;
  available: number;
  utilizationRate: number;
}

