/**
 * Asset Types - Fleet composition for rail/metro systems
 * Generic types that can be configured per deployment
 */

export type AssetType = string; // Configured per deployment (e.g., 'ALSTOM', 'KINKI_SHARYO')

export type AssetStatus = 'OPERATIONAL' | 'IN_MAINTENANCE' | 'OUT_OF_SERVICE';

export interface Asset {
  id: string;
  assetNumber: string;
  assetType: AssetType;
  carsCount: number;
  currentMileageKm: number;
  avgDailyMileageKm: number;
  lastMaintenanceDate: string; // ISO date
  lastMaintenanceKm?: Record<string, number>; // maintenanceTypeId -> km at last maintenance
  status: AssetStatus | string; // Allow string for flexibility
  metadata?: Record<string, unknown>;
}

export interface Fleet {
  id: string;
  name: string;
  assets: Asset[];
  totalAssets: number;
  operationalAssets: number;
}

export interface MileageForecast {
  assetId: string;
  weekNumber: number;
  year: number;
  projectedKm: number;
  cumulativeKm: number;
  confidenceLevel: number; // 0-1
}

/**
 * RUC - Recommended Usage Category
 * Indicates whether a train should accelerate, decelerate, or maintain usage
 */
export type RUCCategory = 'ACCELERATE' | 'NOMINAL' | 'DECELERATE';

export interface RUCStatus {
  assetId: string;
  currentMileageKm: number;
  plannedMileageKm: number;
  driftKm: number;
  category: RUCCategory;
  recommendation: string;
}

