/**
 * Maintenance Types - Based on industry standards
 */

export type MaintenanceLevel = 'A' | 'B' | 'C' | 'D';

export interface MaintenanceType {
  id: string;
  level: MaintenanceLevel;
  name: string;
  description?: string;
  intervalKm: number;
  toleranceKm: number; // Allowed deviation from target
  durationHours: number;
  manHours: number;
  requiredTracks: number;
  estimatedCost: number;
}

export interface MaintenanceEvent {
  id: string;
  assetId: string;
  maintenanceTypeId: string;
  level: MaintenanceLevel;

  // Scheduling
  targetMileageKm: number;
  earliestWeek: number;
  latestWeek: number;
  scheduledWeek?: number;

  // Execution
  status: MaintenanceEventStatus;
  actualStartDate?: string;
  actualEndDate?: string;
  actualMileageKm?: number;

  // Resources
  manHours: number;
  durationHours: number;

  // Metadata
  createdAt: string;
  updatedAt: string;
}

export type MaintenanceEventStatus =
  | 'PLANNED'
  | 'SCHEDULED'
  | 'IN_PROGRESS'
  | 'COMPLETED'
  | 'CANCELLED'
  | 'DEFERRED';

export interface MaintenanceConfig {
  types: MaintenanceType[];
  weeklyCapacityManHours: number;
  concurrentMaintenanceSlots: number;
  operatingHoursPerDay: number;
  maintenanceWindowHours: number;
}

/**
 * Depot configuration
 */
export interface Depot {
  id: string;
  name: string;
  assetTypes: string[]; // Which asset types can be serviced
  trackCount: number;
  weeklyManHours: number;
}

export interface ResourceConstraints {
  weeklyManHours: number;
  monthlyManHours: number;
  maintenanceTracks: number;
  trackCapacityPerDay: number;
  depots: Depot[];
}
